parameters.jsCode:
const root = $json.body ?? $json;
const mail = root.mail ?? root.email ?? null;
const call = root.call ?? root;
const telegram = root.message?.from ? root.message : null;

function clean(v) {
  return v === undefined || v === null || v === '' || v === 'null' ? null : v;
}

function asString(v) {
  return v === undefined || v === null ? null : String(v);
}

const source =
  clean(root.source) ??
  (telegram ? 'telegram' : null) ??
  (mail ? 'email' : null) ??
  (root.sms ? 'sms' : null) ??
  (call?.call_id ? 'call' : null) ??
  'webhook';

const channel =
  clean(root.channel) ??
  (source === 'telegram' ? 'telegram' :
   source === 'email' ? 'mail' :
   source === 'sms' ? 'sms' :
   source === 'call' ? 'phone' :
   'webhook');

const isTelegram = source === 'telegram' || !!telegram;
const tg = telegram ?? {};
const tgFrom = tg.from ?? {};
const tgChat = tg.chat ?? {};

const emailValue =
  clean(root.email) ??
  clean(mail?.from) ??
  clean(mail?.sender) ??
  clean(mail?.reply_to) ??
  null;

const phoneValue =
  clean(root.phone) ??
  clean(root.from) ??
  clean(root.sms?.from) ??
  clean(root.phone_number) ??
  clean(call?.from) ??
  clean(call?.caller) ??
  (isTelegram ? null : null);

const fullNameValue =
  clean(root.full_name) ??
  clean(mail?.from_name) ??
  clean(mail?.name) ??
  (isTelegram ? [tgFrom.first_name, tgFrom.last_name].filter(Boolean).join(' ') || null : null);

const restaurantSlug =
  clean(root.restaurant_slug) ??
  clean(root.slug) ??
  null;

const toValue =
  clean(root.to) ??
  clean(mail?.to) ??
  clean(root.sms?.to) ??
  (isTelegram ? asString(tgChat.id) : null) ??
  null;

const fromValue =
  clean(root.from) ??
  clean(mail?.from) ??
  clean(root.sms?.from) ??
  (isTelegram ? asString(tgFrom.id) : null) ??
  null;

const messageValue =
  clean(root.text) ??
  clean(mail?.text) ??
  clean(mail?.subject) ??
  clean(root.sms?.text) ??
  (isTelegram ? clean(tg.text) : null) ??
  '';

const rawMessageValue = messageValue;

const conversation_id =
  clean(root.conversation_id) ??
  (isTelegram ? `telegram-${tgChat.id ?? tgFrom.id ?? Date.now()}` : null) ??
  (source === 'email' ? `email-${clean(mail?.message_id) ?? Date.now()}` : null) ??
  (source === 'sms' ? `sms-${phoneValue ?? Date.now()}` : null) ??
  (source === 'call' ? `call-${clean(call?.call_id) ?? Date.now()}` : null) ??
  (phoneValue ? `phone-${phoneValue}` : null) ??
  `anon-${Date.now()}`;

return [{
  json: {
    source,
    channel,
    telegram_chat_id: isTelegram ? asString(tgChat.id) : null,
    user_message: messageValue,
    restaurant_slug: restaurantSlug,
    to: toValue,
    from: fromValue,
    phone: clean(root.phone) ?? phoneValue,
    email: emailValue,
    full_name: fullNameValue,
    message: messageValue,
    raw_message: rawMessageValue,
    intent: clean(root.intent),
    requested_datetime: clean(root.requested_datetime),
    party_size: clean(root.party_size),
    special_request: clean(root.special_request),
    call_id: clean(root.call_id) ?? clean(call?.call_id),
    call_status: clean(root.call_status) ?? clean(call?.status),
    conversation_id
  }
}];

parameters.query:
SELECT *
FROM conversation_sessions
WHERE restaurant_id = {{ $('Normalize Restaurant Context').item.json.restaurant_id }}
  AND conversation_id = '{{ $('Normalize Input').item.json.conversation_id }}'
LIMIT 1;

parameters.jsCode:
const restaurant = $('Normalize Restaurant Context').item.json;
const input = $('Normalize Input').item.json;
const loadedSession = $('Load Conversation Session').item.json;

return [{
  json: {
    ...restaurant,

    telegram_chat_id: input.telegram_chat_id ?? null,
    user_message: input.user_message ?? '',
    raw_message: input.raw_message ?? '',
    message: input.message ?? input.user_message ?? '',
    conversation_id: input.conversation_id ?? null,

    source: input.source ?? restaurant.source ?? null,
    channel: input.channel ?? restaurant.channel ?? null,
    to: input.to ?? restaurant.to ?? null,
    from: input.from ?? restaurant.from ?? null,
    phone: input.phone ?? restaurant.phone ?? null,
    email: input.email ?? restaurant.email ?? null,
    full_name: input.full_name ?? restaurant.full_name ?? null,

    intent: input.intent ?? null,
    requested_datetime: input.requested_datetime ?? null,
    party_size: input.party_size ?? null,
    special_request: input.special_request ?? null,
    call_id: input.call_id ?? null,
    call_status: input.call_status ?? null,

    session_state: loadedSession.state ?? {},
    session_id: loadedSession.id ?? null,
    session_status: loadedSession.status ?? 'new'
  }
}];

const sessionContext = $('Merge Session Context').item.json;

function extractFirstJsonObject(text) {
  if (typeof text !== 'string') return text;

  let s = text.trim();

  s = s.replace(/^```json\s*/i, '');
  s = s.replace(/^```\s*/i, '');
  s = s.replace(/```$/i, '');
  s = s.trim();

  const start = s.indexOf('{');
  if (start === -1) return s;

  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      escaped = true;
      continue;
    }

    if (ch === '"') {
      inString = !inString;
      continue;
    }

    if (!inString) {
      if (ch === '{') depth++;
      if (ch === '}') depth--;

      if (depth === 0) {
        return s.slice(start, i + 1);
      }
    }
  }

  return s.slice(start);
}

function keepNewOrPrevious(newValue, oldValue) {
  if (
    newValue === undefined ||
    newValue === null ||
    newValue === '' ||
    newValue === 'null'
  ) {
    return oldValue ?? null;
  }

  return newValue;
}

function parsePartySize(text) {
  if (!text) return null;

  const cleanText = text.toLowerCase();

  const words = {
    'un': 1,
    'une': 1,
    'deux': 2,
    'trois': 3,
    'quatre': 4,
    'cinq': 5,
    'six': 6,
    'sept': 7,
    'huit': 8,
    'neuf': 9,
    'dix': 10,
    'onze': 11,
    'douze': 12
  };

  let match;

  // "7 personnes", "7 pers", "7 couverts"
  match = cleanText.match(/\b(\d{1,2})\s*(?:personnes?|pers|couverts?)\b/i);
  if (match) return Number(match[1]);

  // "table de 7", "table pour 7"
  match = cleanText.match(/\btable\s+(?:de|pour)\s+(\d{1,2})\b/i);
  if (match) return Number(match[1]);

  // "réservation de 7", "réservation pour 7"
  match = cleanText.match(/\bréservation\s+(?:de|pour)\s+(\d{1,2})\b/i);
  if (match) return Number(match[1]);

  // "nous serons 7", "on sera 7", "nous sommes 7", "on est 7"
  match = cleanText.match(/\b(?:nous serons|on sera|nous sommes|on est)\s+(\d{1,2})\b/i);
  if (match) return Number(match[1]);

  // "anniversaire de 6 personnes"
  match = cleanText.match(/\bde\s+(\d{1,2})\s*(?:personnes?|pers|couverts?)\b/i);
  if (match) return Number(match[1]);

  // "pour deux personnes", "deux personnes", "table de sept"
  for (const [word, value] of Object.entries(words)) {
    const explicitWord = new RegExp(`\\b${word}\\s*(?:personnes?|pers|couverts?)\\b`, 'i');
    if (explicitWord.test(cleanText)) return value;

    const tableWord = new RegExp(`\\btable\\s+(?:de|pour)\\s+${word}\\b`, 'i');
    if (tableWord.test(cleanText)) return value;

    const peopleWord = new RegExp(`\\b(?:nous serons|on sera|nous sommes|on est)\\s+${word}\\b`, 'i');
    if (peopleWord.test(cleanText)) return value;
  }

  return null;
}

function parseTime(text) {
  if (!text) return null;

  const cleanText = text.toLowerCase();

  let match = cleanText.match(/\b(\d{1,2})h(\d{2})?\b/i);
  if (match) {
    const hour = String(match[1]).padStart(2, '0');
    const minute = String(match[2] || '00').padStart(2, '0');
    return `${hour}:${minute}:00`;
  }

  match = cleanText.match(/\b(\d{1,2})[:.](\d{2})\b/i);
  if (match) {
    const hour = String(match[1]).padStart(2, '0');
    const minute = String(match[2]).padStart(2, '0');
    return `${hour}:${minute}:00`;
  }

  if (cleanText.includes('midi trente')) return '12:30:00';
  if (cleanText.includes('midi')) return '12:00:00';

  // "mercredi soir", "dimanche soir", "ce soir", etc.
  if (cleanText.includes('soir')) return '20:00:00';

  if (cleanText.includes('déjeuner') || cleanText.includes('dejeuner')) return '12:00:00';
  if (cleanText.includes('dîner') || cleanText.includes('diner')) return '20:00:00';

  return null;
}

function getParisNow(timezone = 'Europe/Paris') {
  return new Date(
    new Date().toLocaleString('en-US', { timeZone: timezone })
  );
}

function getTimezoneOffsetString(date, timezone = 'Europe/Paris') {
  try {
    const parts = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      timeZoneName: 'shortOffset'
    }).formatToParts(date);

    const tz = parts.find(p => p.type === 'timeZoneName')?.value || 'GMT+1';
    const match = tz.match(/GMT([+-])(\d{1,2})(?::(\d{2}))?/);

    if (!match) return '+01:00';

    const sign = match[1];
    const hour = String(match[2]).padStart(2, '0');
    const minute = String(match[3] || '00').padStart(2, '0');

    return `${sign}${hour}:${minute}`;
  } catch (e) {
    return '+01:00';
  }
}

function getNextWeekdayDate(baseDate, weekdayName) {
  const days = {
    'dimanche': 0,
    'lundi': 1,
    'mardi': 2,
    'mercredi': 3,
    'jeudi': 4,
    'vendredi': 5,
    'samedi': 6
  };

  const targetDay = days[weekdayName];
  if (targetDay === undefined) return null;

  const result = new Date(baseDate);
  const currentDay = result.getDay();

  let diff = targetDay - currentDay;

  // Si le jour est aujourd’hui ou déjà passé, on prend le prochain.
  if (diff <= 0) {
    diff += 7;
  }

  result.setDate(result.getDate() + diff);

  return result;
}

function buildDatetime(text, timezone = 'Europe/Paris') {
  if (!text) return null;

  const cleanText = text.toLowerCase();
  const time = parseTime(cleanText);

  // Si pas d’heure exploitable, on ne fabrique pas de fausse date complète.
  if (!time) return null;

  const now = getParisNow(timezone);
  let target = new Date(now);

  const months = {
    'janvier': 0,
    'février': 1,
    'fevrier': 1,
    'mars': 2,
    'avril': 3,
    'mai': 4,
    'juin': 5,
    'juillet': 6,
    'août': 7,
    'aout': 7,
    'septembre': 8,
    'octobre': 9,
    'novembre': 10,
    'décembre': 11,
    'decembre': 11
  };

  // "mercredi 17 juin", "17 juin"
  const explicitDate = cleanText.match(/\b(?:dimanche|lundi|mardi|mercredi|jeudi|vendredi|samedi)?\s*(\d{1,2})\s+(janvier|février|fevrier|mars|avril|mai|juin|juillet|août|aout|septembre|octobre|novembre|décembre|decembre)\b/i);

  if (explicitDate) {
    const day = Number(explicitDate[1]);
    const month = months[explicitDate[2].toLowerCase()];
    let year = now.getFullYear();

    target = new Date(now);
    target.setFullYear(year, month, day);

    // Si la date est déjà passée, on prend l’année suivante.
    if (target < now) {
      target.setFullYear(year + 1, month, day);
    }
  } else {
    const weekdayMatch = cleanText.match(/\b(dimanche|lundi|mardi|mercredi|jeudi|vendredi|samedi)\b/i);

    if (weekdayMatch) {
      const weekday = weekdayMatch[1].toLowerCase();
      target = getNextWeekdayDate(now, weekday) || target;
    } else if (cleanText.includes('demain')) {
      target.setDate(target.getDate() + 1);
    } else if (cleanText.includes('ce soir')) {
      // aujourd’hui
    }
  }

  const yyyy = target.getFullYear();
  const mm = String(target.getMonth() + 1).padStart(2, '0');
  const dd = String(target.getDate()).padStart(2, '0');

  const offset = getTimezoneOffsetString(target, timezone);

  return `${yyyy}-${mm}-${dd}T${time}${offset}`;
}

function hasDateWithoutTime(text) {
  if (!text) return false;

  const cleanText = text.toLowerCase();

  const hasDate =
    /\b(demain|dimanche|lundi|mardi|mercredi|jeudi|vendredi|samedi|\d{1,2}\s+(janvier|février|fevrier|mars|avril|mai|juin|juillet|août|aout|septembre|octobre|novembre|décembre|decembre))\b/i.test(cleanText);

  const hasTime = !!parseTime(cleanText);

  return hasDate && !hasTime;
}

function parseFullName(text, previousState) {
  if (!text) return null;

  const cleanText = text.trim();

  // Cas explicites :
  // "au nom de Jeremy"
  // "nom de Jeremy"
  // "réservation au nom de Jeremy"
  const match = cleanText.match(/\b(?:au nom de|nom de|pour le nom|réservation au nom de)\s+([a-zA-ZÀ-ÿ' -]{2,60})$/i);
  if (match) {
    return match[1].trim();
  }

  const waitingForName =
    Array.isArray(previousState.missing_fields) &&
    previousState.missing_fields.includes('full_name');

  const stageWaitingName =
    previousState.stage === 'collecting_information' ||
    previousState.stage === 'waiting_user';

  const looksLikeOnlyName =
    /^[a-zA-ZÀ-ÿ' -]{2,40}$/.test(cleanText) &&
    cleanText.split(/\s+/).length <= 3;

  const forbiddenWords = [
    'bonjour',
    'salut',
    'hello',
    'oui',
    'non',
    'ok',
    'okay',
    'je confirme',
    'confirmé',
    'confirme',
    'c’est bon',
    "c'est bon",
    'c’est ça',
    "c'est ça",
    'exactement',
    'parfait',
    'merci',
    'validé',
    'valide',
    'c’est correct',
    "c'est correct",
    'annuler',
    'annule'
  ];

  const lower = cleanText.toLowerCase();

  if (
    (waitingForName || stageWaitingName) &&
    looksLikeOnlyName &&
    !forbiddenWords.includes(lower)
  ) {
    return cleanText;
  }

  return null;
}

function parseSpecialRequest(text) {
  if (!text) return null;

  const cleanText = text.toLowerCase();
  const requests = [];

  if (cleanText.includes('terrasse')) {
    requests.push('Table en terrasse');
  }

  if (cleanText.includes('anniversaire')) {
    requests.push('Anniversaire');
  }

  if (cleanText.includes('chaise bébé') || cleanText.includes('chaise bebe')) {
    requests.push('Chaise bébé');
  }

  if (cleanText.includes('allergie')) {
    requests.push('Allergie signalée');
  }

  if (cleanText.includes('calme')) {
    requests.push('Table au calme');
  }

  if (cleanText.includes('enfant') || cleanText.includes('enfants')) {
    requests.push('Présence d’enfant(s)');
  }

  return requests.length > 0 ? requests.join(', ') : null;
}

function isNewReservationRequest(text) {
  if (!text) return false;

  const cleanText = text.toLowerCase();

  const hasReservationIntent =
    /\b(réserver|reserver|réservation|reservation|table|manger|déjeuner|dejeuner|dîner|diner)\b/i.test(cleanText);

  const hasModificationIntent =
    /\b(modifier|changer|décaler|decaler|annuler|déplacer|deplacer|remplacer|finalement|plutôt|plutot|au lieu de)\b/i.test(cleanText);

  const hasDateOrTimeOrParty =
    /\b(ce soir|demain|dimanche|lundi|mardi|mercredi|jeudi|vendredi|samedi|\d{1,2}h|\d{1,2}:\d{2}|\d{1,2}\s*(personnes?|pers|couverts?)|un|une|deux|trois|quatre|cinq|six|sept|huit|neuf|dix)\b/i.test(cleanText);

  return hasReservationIntent && hasDateOrTimeOrParty && !hasModificationIntent;
}

function formatDateHumanFr(iso, timezone = 'Europe/Paris') {
  if (!iso) return null;

  const d = new Date(iso);

  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric',
    timeZone: timezone
  });

  const time = d.toLocaleTimeString('fr-FR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: timezone
  });

  return `${date} à ${time}`;
}

let payload = null;
let parse_error = null;
let raw = $json;

try {
  let value = $json.output ?? $json.text ?? $json.response ?? $json;

  if (typeof value === 'string') {
    value = extractFirstJsonObject(value);
    payload = JSON.parse(value);
  } else if (typeof value === 'object' && value !== null) {
    if (typeof value.output === 'string') {
      const cleaned = extractFirstJsonObject(value.output);
      payload = JSON.parse(cleaned);
    } else if (typeof value.output === 'object' && value.output !== null) {
      payload = value.output;
    } else {
      payload = value;
    }
  }
} catch (e) {
  parse_error = e.message;
}

const previousState = sessionContext.session_state || {};
const extracted = payload?.extracted_data ?? {};

const message =
  sessionContext.user_message ||
  sessionContext.raw_message ||
  sessionContext.message ||
  '';

const newReservationRequest = isNewReservationRequest(message);

const parsedDatetime = buildDatetime(
  message,
  sessionContext.timezone ?? 'Europe/Paris'
);

const parsedPartySize = parsePartySize(message);

const parsedFullName = parseFullName(message, previousState);

const parsedSpecialRequest = parseSpecialRequest(message);

const dateWithoutTime = hasDateWithoutTime(message);

// Nouvelle réservation : on réinitialise date/personnes/demande spéciale.
// Mais on conserve le nom connu du client.
const requested_datetime = newReservationRequest
  ? keepNewOrPrevious(extracted.requested_datetime ?? parsedDatetime, null)
  : keepNewOrPrevious(extracted.requested_datetime ?? parsedDatetime, previousState.requested_datetime);

const party_size = newReservationRequest
  ? keepNewOrPrevious(extracted.party_size ?? parsedPartySize, null)
  : keepNewOrPrevious(extracted.party_size ?? parsedPartySize, previousState.party_size);

const full_name = keepNewOrPrevious(
  extracted.full_name ?? parsedFullName,
  previousState.full_name
);

const phone = keepNewOrPrevious(
  extracted.phone,
  previousState.phone
);

const email = keepNewOrPrevious(
  extracted.email,
  previousState.email
);

const special_request = newReservationRequest
  ? keepNewOrPrevious(extracted.special_request ?? parsedSpecialRequest, null)
  : keepNewOrPrevious(extracted.special_request ?? parsedSpecialRequest, previousState.special_request);

const missing_fields = [];

if (!requested_datetime) missing_fields.push('requested_datetime');
if (!party_size) missing_fields.push('party_size');
if (!full_name) missing_fields.push('full_name');

let reply =
  payload?.reply ??
  "Bonjour, pouvez-vous me préciser la date, l’heure et le nombre de personnes pour votre réservation ?";

const greetingName = full_name ? ` ${full_name}` : '';

// Cas : date repérée mais heure manquante
if (!requested_datetime && party_size && dateWithoutTime) {
  reply =
`Bonjour${greetingName}, j’ai bien noté votre demande pour ${party_size} personne${Number(party_size) > 1 ? 's' : ''}${special_request ? `\n📝 Demande : ${special_request}` : ''}.

Il me manque juste l’heure souhaitée pour finaliser la demande.`;
}

// Cas : date/heure OK + nombre OK, mais nom manquant
if (requested_datetime && party_size && !full_name) {
  reply =
`Très bien, j’ai noté votre demande.

📅 Date : ${formatDateHumanFr(requested_datetime, sessionContext.timezone ?? 'Europe/Paris')}
👥 Nombre de personnes : ${party_size}${special_request ? `\n📝 Demande : ${special_request}` : ''}

À quel nom dois-je mettre la réservation ?`;
}

// Cas : tout est OK
if (requested_datetime && party_size && full_name) {
  const humanDate = formatDateHumanFr(
    requested_datetime,
    sessionContext.timezone ?? 'Europe/Paris'
  );

  reply =
`Bonjour${greetingName}, je récapitule votre réservation :

📅 Date : ${humanDate}
👤 Nom : ${full_name}
👥 Nombre de personnes : ${party_size}${special_request ? `\n📝 Demande : ${special_request}` : ''}

Pouvez-vous confirmer ?`;
}

return [
  {
    json: {
      telegram_chat_id:
        sessionContext.telegram_chat_id ??
        sessionContext.to ??
        sessionContext.from ??
        null,

      reply,
      decision: missing_fields.length > 0 ? 'need_followup' : 'ready_to_check_availability',
      needs_followup: missing_fields.length > 0,

      missing_fields,

      special_requests: Array.isArray(payload?.special_requests)
        ? payload.special_requests
        : [],

      requested_datetime,
      party_size,
      full_name,
      phone,
      email,
      special_request,

      restaurant_id: sessionContext.restaurant_id ?? null,
      restaurant_name: sessionContext.restaurant_name ?? null,
      restaurant_slug: sessionContext.restaurant_slug ?? null,
      timezone: sessionContext.timezone ?? 'Europe/Paris',
      default_meal_duration_minutes: sessionContext.default_meal_duration_minutes ?? 120,
      cleaning_buffer_minutes: sessionContext.cleaning_buffer_minutes ?? 15,
      max_party_size: sessionContext.max_party_size ?? 12,

      source: sessionContext.source ?? null,
      channel: sessionContext.channel ?? null,
      to: sessionContext.to ?? null,
      from: sessionContext.from ?? null,
      phone_input: sessionContext.phone ?? null,

      message,
      raw_message: message,

      booking_policy: sessionContext.booking_policy ?? null,
      event_notification_policy: sessionContext.event_notification_policy ?? null,
      conversation_id: sessionContext.conversation_id ?? null,
      session_state: previousState,

      parser_ok: !!payload?.reply,
      parse_error,

      new_reservation_request: newReservationRequest,
      date_without_time: dateWithoutTime,

      manual_datetime_parser_used: !!parsedDatetime,
      manual_party_size_parser_used: !!parsedPartySize,
      manual_full_name_parser_used: !!parsedFullName,
      manual_special_request_parser_used: !!parsedSpecialRequest,

      parsed_full_name: parsedFullName,
      parsed_special_request: parsedSpecialRequest,

      raw_agent_output: raw,
      parsed_agent_payload: payload
    }
  }
];

parameters.query:
SELECT *
FROM clients
WHERE restaurant_id = {{ $json.restaurant_id ?? 1 }}
AND (
  ('{{ $json.from ?? "" }}' <> '' AND phone = '{{ $json.from ?? "" }}')
  OR
  ('{{ $json.email ?? "" }}' <> '' AND email = '{{ $json.email ?? "" }}')
)
LIMIT 1;

parameters.jsCode:
const input = $json;

return [{
  json: {
    ...input,
    restaurant_id: input.restaurant_id ?? null,
