      last_agent_reply: "Bonjour, je n’arrive pas à identifier le restaurant associé à ce canal. Pouvez-vous vérifier la configuration ou préciser le restaurant concerné ?"
    }
  }
];

const input = $json;
const previousState = input.session_state || {};

function keepNewOrPrevious(newValue, oldValue) {
  if (newValue === undefined || newValue === null || newValue === '' || newValue === 'null') {
    return oldValue ?? null;
  }
  return newValue;
}

const extracted = {
  requested_datetime: keepNewOrPrevious(input.requested_datetime, previousState.requested_datetime),
  party_size: keepNewOrPrevious(input.party_size, previousState.party_size),
  full_name: keepNewOrPrevious(input.full_name, previousState.full_name),
  phone: keepNewOrPrevious(input.phone ?? input.phone_input, previousState.phone),
  email: keepNewOrPrevious(input.email, previousState.email),
  special_request: keepNewOrPrevious(input.special_request, previousState.special_request),
};

const missingFields = [];

if (!extracted.requested_datetime) {
  missingFields.push('requested_datetime');
}

if (!extracted.party_size) {
  missingFields.push('party_size');
}

if (!extracted.full_name) {
  missingFields.push('full_name');
}

const stage = missingFields.length > 0 ? 'collecting_information' : 'ready_to_check_availability';

const state = {
  ...previousState,
  ...extracted,
  missing_fields: missingFields,
  stage,
  last_intent: input.decision ?? 'need_followup',
  updated_at: new Date().toISOString()
};

function sqlString(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlJson(value) {
  return `'${JSON.stringify(value).replace(/'/g, "''")}'::jsonb`;
}

return [
  {
    json: {
      ...input,
      state,
      state_sql: sqlJson(state),
      restaurant_id_sql: Number(input.restaurant_id),
      conversation_id_sql: sqlString(input.conversation_id),
      telegram_chat_id_sql: sqlString(input.telegram_chat_id),
      last_message_sql: sqlString(input.message || input.raw_message || ''),
      last_agent_reply_sql: sqlString(input.reply || 'Bonjour, comment puis-je vous aider pour votre réservation ?'),
      status_sql: sqlString('active')
    }
  }
];

const input = $json;
const state = input.state || input.session_state || {};

const restaurantName =
  input.restaurant_name ||
  state.restaurant_name ||
  'Thysiane House';

const fullName =
  input.full_name ||
  state.full_name ||
  null;

const requestedDatetime =
  input.requested_datetime ||
  state.requested_datetime ||
  null;

const partySize =
  input.party_size ||
  state.party_size ||
  null;

function formatDateFr(iso) {
  if (!iso) return null;

  const d = new Date(iso);
  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    timeZone: 'Europe/Paris'
  });

  const time = d.toLocaleTimeString('fr-FR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Europe/Paris'
  });

  return `${date} à ${time}`;
}

const dateFr = formatDateFr(requestedDatetime);

let finalReply = input.reply;

const hasAllRequired =
  fullName &&
  requestedDatetime &&
  partySize;

const isAvailable =
  input.is_available === true ||
  input.availability_status === 'available' ||
  input.is_closed === false;

if (hasAllRequired && isAvailable) {
  finalReply = `Réservation OK pour ${fullName} pour ${dateFr} pour ${partySize} personne${Number(partySize) > 1 ? 's' : ''} au restaurant ${restaurantName}.`;
}

return [
  {
    json: {
      ...input,
      reply: finalReply,
      last_agent_reply: finalReply,
      full_name: fullName,
      requested_datetime: requestedDatetime,
      party_size: partySize,
      restaurant_name: restaurantName
    }
  }
];

const base = $('Before Check Closure').item.json;
const closure = $('Check Closure').item.json || {};

const state = base.session_state || {};

function keepNewOrPrevious(newValue, oldValue) {
  if (
    newValue === undefined ||
    newValue === null ||
    newValue === '' ||
    newValue === 'null'
  ) {
    return oldValue ?? null;
  }

  return newValue;
}

function formatDateHumanFr(iso, timezone = 'Europe/Paris') {
  if (!iso) return null;

  const d = new Date(iso);

  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric',
    timeZone: timezone
  });

  const time = d.toLocaleTimeString('fr-FR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: timezone
  });

  return `${date} à ${time}`;
}

const requested_datetime = keepNewOrPrevious(
  base.requested_datetime,
  state.requested_datetime
);

const party_size = keepNewOrPrevious(
  base.party_size,
  state.party_size
);

const full_name = keepNewOrPrevious(
  base.full_name,
  state.full_name
);

const phone = keepNewOrPrevious(
  base.phone,
  state.phone
);

const email = keepNewOrPrevious(
  base.email,
  state.email
);

const special_request = keepNewOrPrevious(
  base.special_request,
  state.special_request
);

const message = String(base.raw_message || base.message || '').toLowerCase();

const customer_confirmed =
  /\b(oui|ok|okay|c'est bon|c’est bon|c'est ça|c’est ça|exactement|je confirme|confirmé|confirme|validé|valide|parfait|go)\b/i.test(message);

const customer_cancelled =
  /\b(non|annule|annuler|j'annule|j’annule|pas bon|ce n'est pas bon|ce n’est pas bon)\b/i.test(message);

const hasRequired =
  !!requested_datetime &&
  !!party_size &&
  !!full_name;

const is_closed =
  closure.is_closed === true ||
  closure.is_closed === 'true' ||
  closure.is_closed === 1 ||
  closure.is_closed === '1';

const is_available = !is_closed;

const timezone = base.timezone || 'Europe/Paris';
const humanDate = formatDateHumanFr(requested_datetime, timezone);

let reply = base.reply || 'Très bien, je vérifie votre demande.';
let should_create_reservation = false;
let availability_status = 'unknown';
let decision = base.decision || 'need_followup';

if (customer_cancelled) {
  decision = 'cancel';
  availability_status = 'cancelled';
  should_create_reservation = false;

  reply =
`Très bien, j’annule cette demande de réservation.

Je reste disponible si vous souhaitez choisir un autre créneau.`;

} else if (is_closed) {
  decision = 'unavailable';
  availability_status = 'closed';
  should_create_reservation = false;

  reply =
`Désolé, le restaurant est fermé sur ce créneau${closure.closure_reason ? ` : ${closure.closure_reason}` : ''}.

Souhaitez-vous choisir une autre date ou un autre horaire ?`;

} else if (!hasRequired) {
  decision = 'need_followup';
  availability_status = 'missing_information';
  should_create_reservation = false;

  const missing = [];

  if (!requested_datetime) missing.push('la date et l’heure');
  if (!party_size) missing.push('le nombre de personnes');
  if (!full_name) missing.push('le nom de la réservation');

  if (requested_datetime && party_size && !full_name) {
    reply =
`Très bien, j’ai noté votre demande.

📅 Date : ${humanDate}
👥 Nombre de personnes : ${party_size}

À quel nom dois-je mettre la réservation ?`;
  } else if (requested_datetime && !party_size) {
    reply =
`Très bien, j’ai noté la date.

📅 Date : ${humanDate}

Pour combien de personnes souhaitez-vous réserver ?`;
  } else if (!requested_datetime && party_size) {
    reply =
`Très bien, j’ai noté pour ${party_size} personne${Number(party_size) > 1 ? 's' : ''}.

Pour quelle date et quelle heure souhaitez-vous réserver ?`;
  } else {
    reply =
`Pouvez-vous me préciser ${missing.join(', ')} pour votre réservation ?`;
  }

} else if (hasRequired && !customer_confirmed) {
  decision = 'ready_to_check_availability';
  availability_status = 'waiting_confirmation';
  should_create_reservation = false;

  reply =
`Je récapitule votre réservation :

📅 Date : ${humanDate}
👤 Nom : ${full_name}
👥 Nombre de personnes : ${party_size}

Pouvez-vous confirmer ?`;

} else if (hasRequired && customer_confirmed && is_available) {
  decision = 'confirm';
  availability_status = 'available';
  should_create_reservation = true;

  reply =
`Parfait, je crée votre réservation.

📅 Date : ${humanDate}
👤 Nom : ${full_name}
👥 Nombre de personnes : ${party_size}`;
}

return [
  {
    json: {
      ...base,

      requested_datetime,
      party_size,
      full_name,
      phone,
      email,
      special_request,

      is_closed,
      is_available,
      closure_reason: closure.closure_reason ?? null,

      customer_confirmed,
      customer_cancelled,
      should_create_reservation,
      availability_status,

      decision,
      reply,
      last_agent_reply: reply,

      human_requested_datetime: humanDate,
      timezone
    }
  }
];

const base = $('Before Check Closure').item.json;

// Si tu veux récupérer le résultat du IF ou des nœuds intermédiaires, adapte selon ton workflow
let client = {};
try {
  client = $('Find Client').item.json || {};
} catch (e) {}

let closure = {};
try {
