const decision = $('Build Availability Decision').item.json;

const restaurantName = decision.restaurant_name || 'le restaurant';
const fullName = decision.full_name;
const partySize = decision.party_size;

function formatDateHumanFr(iso, timezone = 'Europe/Paris') {
  if (!iso) return null;

  const d = new Date(iso);

  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric',
    timeZone: timezone
  });

  const time = d.toLocaleTimeString('fr-FR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: timezone
  });

  return `${date} à ${time}`;
}

const dateFr = formatDateHumanFr(
  reservation.start_time,
  decision.timezone || 'Europe/Paris'
);

const reply =
`✅ Réservation confirmée !

📅 Date : ${dateFr}
👤 Nom : ${fullName}
👥 Nombre de personnes : ${partySize}
🍽️ Restaurant : ${restaurantName}

Merci, à bientôt.`;

return [
  {
    json: {
      ...decision,
      reservation_id: reservation.id,
