function nodeJson(name) {
  try {
    return $(name).item.json || {};
  } catch (e) {
    return {};
  }
}

function hasValue(v) {
  return v !== undefined && v !== null && v !== '';
}

function readFieldFrom(obj, field) {
  const candidates = [
    obj?.[field],
    obj?.body?.[field],
    obj?.body?.args?.[field],
    obj?.body?.arguments?.[field],
    obj?.args?.[field],
    obj?.arguments?.[field],
    obj?.query?.[field]
  ];

  return candidates.find(hasValue);
}

const verifyJson = nodeJson('Verify Channel Source');
