const markJson = nodeJson('Mark Retell Voice Source');

function pickField(field, fallback = null) {
  const sources = [
    verifyJson,
    markJson,
    webhookJson
  ];

  for (const source of sources) {
    const value = readFieldFrom(source, field);
    if (hasValue(value)) return value;
  }

  return fallback;
}

