function pad(n) {
  return String(n).padStart(2, '0');
}

function normalizeText(v) {
  return String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[’']/g, ' ')
    .replace(/-/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function formatDateHumanFr(iso, timezone = 'Europe/Paris') {
  if (!iso) return null;

  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return null;

  const date = d.toLocaleDateString('fr-FR', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    timeZone: timezone
  });

  const parts = new Intl.DateTimeFormat('fr-FR', {
    hour: 'numeric',
    minute: '2-digit',
    hour12: false,
    timeZone: timezone
  }).formatToParts(d);

  const hour = Number(parts.find(p => p.type === 'hour')?.value ?? 0);
  const minute = Number(parts.find(p => p.type === 'minute')?.value ?? 0);

  let timeLabel;

  if (hour === 12 && minute === 0) {
    timeLabel = 'midi';
  } else if (hour === 12 && minute === 30) {
    timeLabel = 'midi trente';
  } else if (minute === 0) {
    timeLabel = `${hour} heure${hour > 1 ? 's' : ''}`;
  } else {
    timeLabel = `${hour}h${pad(minute)}`;
  }

  return `${date} à ${timeLabel}`;
}

function getTimezoneOffsetMinutes(date, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', {
    timeZone,
    hour12: false,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  });

  const parts = dtf.formatToParts(date).reduce((acc, part) => {
    if (part.type !== 'literal') acc[part.type] = part.value;
    return acc;
  }, {});

  const asUTC = Date.UTC(
    Number(parts.year),
    Number(parts.month) - 1,
    Number(parts.day),
    Number(parts.hour),
    Number(parts.minute),
    Number(parts.second)
  );

  return (asUTC - date.getTime()) / 60000;
}

function offsetToString(offsetMinutes) {
  const sign = offsetMinutes >= 0 ? '+' : '-';
  const abs = Math.abs(offsetMinutes);
  const h = Math.floor(abs / 60);
  const m = abs % 60;
  return `${sign}${pad(h)}:${pad(m)}`;
}

function makeZonedIso(year, monthIndex, day, hour, minute, timezone = 'Europe/Paris') {
  const utcGuess = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0));
  let offset = getTimezoneOffsetMinutes(utcGuess, timezone);

  let utcDate = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0) - offset * 60000);
  offset = getTimezoneOffsetMinutes(utcDate, timezone);

  utcDate = new Date(Date.UTC(year, monthIndex, day, hour, minute, 0) - offset * 60000);

  return {
    iso: `${year}-${pad(monthIndex + 1)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00${offsetToString(offset)}`,
    utcDate,
    offset
  };
}

function getParisParts(date, timezone = 'Europe/Paris') {
  const parts = new Intl.DateTimeFormat('fr-FR', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'long',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).formatToParts(date).reduce((acc, part) => {
    if (part.type !== 'literal') acc[part.type] = part.value;
    return acc;
  }, {});

  const weekdays = {
    dimanche: 0,
    lundi: 1,
    mardi: 2,
    mercredi: 3,
    jeudi: 4,
    vendredi: 5,
    samedi: 6
  };

  return {
    year: Number(parts.year),
    monthIndex: Number(parts.month) - 1,
    day: Number(parts.day),
    weekday: weekdays[normalizeText(parts.weekday)],
    hour: Number(parts.hour),
    minute: Number(parts.minute)
  };
}

function wordsToNumber(text) {
  const t = normalizeText(text);

  const numbers = {
    'un': 1,
    'une': 1,
    'deux': 2,
    'trois': 3,
    'quatre': 4,
    'cinq': 5,
    'six': 6,
    'sept': 7,
    'huit': 8,
    'neuf': 9,
    'dix': 10,
    'onze': 11,
    'douze': 12,
    'treize': 13,
    'quatorze': 14,
    'quinze': 15,
    'seize': 16,
    'dix sept': 17,
    'dix huit': 18,
    'dix neuf': 19,
    'vingt': 20,
    'vingt et un': 21,
    'vingt et une': 21,
    'vingt deux': 22,
    'vingt trois': 23,
    'vingt quatre': 24,
    'vingt cinq': 25,
    'vingt six': 26,
    'vingt sept': 27,
    'vingt huit': 28,
    'vingt neuf': 29,
    'trente': 30,
    'trente et un': 31
  };

  if (/^\d+$/.test(t)) return Number(t);

  return numbers[t] ?? null;
}

function parseDateText(dateText, currentDate, timezone = 'Europe/Paris') {
  const raw = normalizeText(dateText);
  const base = getParisParts(currentDate, timezone);

  const weekdays = {
    dimanche: 0,
    lundi: 1,
    mardi: 2,
    mercredi: 3,
    jeudi: 4,
    vendredi: 5,
    samedi: 6
  };

  const months = {
    janvier: 0,
    fevrier: 1,
    mars: 2,
    avril: 3,
    mai: 4,
    juin: 5,
    juillet: 6,
    aout: 7,
    septembre: 8,
    octobre: 9,
    novembre: 10,
    decembre: 11
  };

  let year = base.year;
  let monthIndex = base.monthIndex;
  let day = base.day;

  if (raw.includes('aujourd')) {
    return { year, monthIndex, day };
  }

  if (raw.includes('demain')) {
    const d = new Date(Date.UTC(base.year, base.monthIndex, base.day, 12, 0, 0));
    d.setUTCDate(d.getUTCDate() + 1);
    return {
      year: d.getUTCFullYear(),
      monthIndex: d.getUTCMonth(),
      day: d.getUTCDate()
    };
  }

  const absoluteMatch = raw.match(/(?:lundi|mardi|mercredi|jeudi|vendredi|samedi|dimanche)?\s*(\d{1,2}|un|une|deux|trois|quatre|cinq|six|sept|huit|neuf|dix|onze|douze|treize|quatorze|quinze|seize|dix sept|dix huit|dix neuf|vingt|vingt et un|vingt et une|vingt deux|vingt trois|vingt quatre|vingt cinq|vingt six|vingt sept|vingt huit|vingt neuf|trente|trente et un)\s+(janvier|fevrier|mars|avril|mai|juin|juillet|aout|septembre|octobre|novembre|decembre)(?:\s+(\d{4}|deux mille vingt six|deux mille vingt sept))?/);

  if (absoluteMatch) {
    const parsedDay = wordsToNumber(absoluteMatch[1]);
    const parsedMonth = months[absoluteMatch[2]];

    let parsedYear = base.year;

    if (absoluteMatch[3]) {
      const y = normalizeText(absoluteMatch[3]);
      if (/^\d{4}$/.test(y)) parsedYear = Number(y);
      if (y === 'deux mille vingt six') parsedYear = 2026;
      if (y === 'deux mille vingt sept') parsedYear = 2027;
    }

    const candidate = makeZonedIso(parsedYear, parsedMonth, parsedDay, 12, 0, timezone).utcDate;

    if (candidate < currentDate && !absoluteMatch[3]) {
      parsedYear += 1;
    }

    return {
      year: parsedYear,
      monthIndex: parsedMonth,
      day: parsedDay
    };
  }

  for (const [weekdayName, targetWeekday] of Object.entries(weekdays)) {
    if (raw.includes(weekdayName)) {
      let delta = (targetWeekday - base.weekday + 7) % 7;

      if (delta === 0) {
        delta = 7;
      }

      const d = new Date(Date.UTC(base.year, base.monthIndex, base.day, 12, 0, 0));
      d.setUTCDate(d.getUTCDate() + delta);

      return {
        year: d.getUTCFullYear(),
        monthIndex: d.getUTCMonth(),
        day: d.getUTCDate()
      };
    }
  }

  return null;
}

function parseTimeText(dateText, timeText) {
  const raw = normalizeText(`${dateText || ''} ${timeText || ''}`);

  if (raw.includes('midi trente') || raw.includes('midi et demi') || raw.includes('12h30') || raw.includes('12 h 30')) {
    return { hour: 12, minute: 30 };
  }

  if (raw.includes('midi quart') || raw.includes('midi et quart') || raw.includes('12h15') || raw.includes('12 h 15')) {
    return { hour: 12, minute: 15 };
  }

  if (raw.includes('midi moins le quart') || raw.includes('11h45') || raw.includes('11 h 45')) {
    return { hour: 11, minute: 45 };
  }

  if (raw.includes('midi')) {
    return { hour: 12, minute: 0 };
  }

  if (raw.includes('soir')) {
    const explicitTime = parseExplicitTime(raw);
    if (explicitTime) {
      if (explicitTime.hour >= 1 && explicitTime.hour <= 11) {
        explicitTime.hour += 12;
      }
      return explicitTime;
    }

    return { hour: 19, minute: 0 };
  }

  const explicitTime = parseExplicitTime(raw);
  if (explicitTime) return explicitTime;

  return null;
}

function parseExplicitTime(raw) {
  let match = raw.match(/(\d{1,2})\s*h\s*(\d{1,2})?/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: match[2] ? Number(match[2]) : 0
    };
  }

  match = raw.match(/(\d{1,2})\s*:\s*(\d{2})/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: Number(match[2])
    };
  }

  match = raw.match(/(\d{1,2})\s*heures?\s*(\d{1,2})?/);
  if (match) {
    return {
      hour: Number(match[1]),
      minute: match[2] ? Number(match[2]) : 0
    };
  }

  const wordHours = [
    ['vingt trois', 23],
    ['vingt deux', 22],
    ['vingt et une', 21],
    ['vingt et un', 21],
    ['vingt', 20],
    ['dix neuf', 19],
    ['dix huit', 18],
    ['dix sept', 17],
    ['seize', 16],
    ['quinze', 15],
    ['quatorze', 14],
    ['treize', 13],
    ['douze', 12],
    ['onze', 11],
    ['dix', 10],
    ['neuf', 9],
    ['huit', 8],
    ['sept', 7],
    ['six', 6],
    ['cinq', 5],
    ['quatre', 4],
    ['trois', 3],
    ['deux', 2],
    ['une', 1],
    ['un', 1]
  ];

  for (const [label, hour] of wordHours) {
    if (raw.includes(`${label} heure`) || raw.includes(`${label} heures`)) {
      let minute = 0;

      if (raw.includes('trente')) minute = 30;
      if (raw.includes('quart')) minute = 15;
      if (raw.includes('moins le quart')) {
        return {
          hour: hour - 1,
          minute: 45
        };
      }

      return { hour, minute };
    }
  }

  return null;
}

